import { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Fix for default Leaflet marker icons in React
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

const workerIcon = L.icon({
    iconUrl: 'https://cdn-icons-png.flaticon.com/512/1986/1986937.png', // Delivery/Worker bike style icon
    iconSize: [40, 40],
    iconAnchor: [20, 20],
    popupAnchor: [0, -20],
    className: 'worker-marker-animate' // We will add CSS for smooth transition if possible
});

// Helper component to auto-center map when worker moves
const RecenterMap = ({ lat, lng }: { lat: number; lng: number }) => {
    const map = useMap();
    useEffect(() => {
        map.flyTo([lat, lng], map.getZoom());
    }, [lat, lng, map]);
    return null;
};

interface Location {
    coordinates: [number, number]; // [Longitude, Latitude] from PostGIS
}

interface LiveTrackingMapProps {
    location: Location | null;
}

const LiveTrackingMap = ({ location }: LiveTrackingMapProps) => {
    // Default to a fallback location if data is missing (e.g., City Center fallback)
    // PostGIS is [Lng, Lat], Leaflet needs [Lat, Lng]
    const position: [number, number] = location
        ? [location.coordinates[1], location.coordinates[0]]
        : [11.0168, 76.9558]; // Example: Coimbatore

    if (!location) return (
        <div className="h-full w-full bg-secondary/20 animate-pulse flex items-center justify-center text-muted-foreground">
            Waiting for GPS signal...
        </div>
    );

    return (
        <MapContainer
            center={position}
            zoom={15}
            style={{ height: "100%", width: "100%" }}
            zoomControl={false}
        >
            <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />

            {/* The Worker's Marker */}
            <Marker position={position} icon={workerIcon}>
                <Popup>
                    Worker is here
                </Popup>
            </Marker>

            {/* Auto-follow the worker */}
            <RecenterMap lat={position[0]} lng={position[1]} />
        </MapContainer>
    );
};

export default LiveTrackingMap;
